var CONVERSATIONS_SQ_ZH = [
{ title: "Porositje në një kafene në Chengdu", scene: "Je në një kafene të vogël në Chengdu pas një shëtitjeje. Dëshiron një kafe pa sheqer dhe pyet nëse mund të karikosh telefonin.", lines: [{ who: "them", zh: "你好，请问要喝什么？", sq: "Përshëndetje, çfarë dëshironi të pini?" }, { who: "you", zh: "我要一杯咖啡。", sq: "Dua një kafe." }, { who: "them", zh: "要热的还是冰的？", sq: "E doni të nxehtë apo me akull?" }, { who: "you", zh: "热的，不要糖。", sq: "Të nxehtë, pa sheqer." }, { who: "them", zh: "要加牛奶吗？", sq: "Doni të shtoni qumësht?" }, { who: "you", zh: "要，加一点牛奶。", sq: "Po, shtoni pak qumësht." }, { who: "them", zh: "好的，一共二十五块。", sq: "Në rregull, gjithsej 25 juanë." }, { who: "you", zh: "可以刷卡吗？", sq: "A mund të paguaj me kartë?" }, { who: "them", zh: "可以。", sq: "Po, mundeni." }, { who: "you", zh: "这里可以充电吗？", sq: "A mund të karikoj telefonin këtu?" }, { who: "them", zh: "可以，插座在右边。", sq: "Po, priza është në të djathtë." }, { who: "you", zh: "谢谢你。", sq: "Faleminderit." }] },
{ title: "Regjistrim në hotel në Makao", scene: "Arrin në hotelin tënd në Makao në mbrëmje. Ke rezervim dhe duhet të tregosh pasaportën në recepsion.", lines: [{ who: "them", zh: "您好，欢迎光临。", sq: "Përshëndetje, mirë se erdhët." }, { who: "you", zh: "您好，我有预订。", sq: "Përshëndetje, kam rezervim." }, { who: "them", zh: "请问您叫什么名字？", sq: "Si quheni, ju lutem?" }, { who: "you", zh: "我叫阿尔班。", sq: "Quhem Arban." }, { who: "them", zh: "请出示护照。", sq: "Ju lutem tregoni pasaportën." }, { who: "you", zh: "这是我的护照。", sq: "Kjo është pasaporta ime." }, { who: "them", zh: "您订的是双人间，两晚。", sq: "Keni rezervuar dhomë dyshe për dy net." }, { who: "you", zh: "对，房间在哪里？", sq: "Po, ku është dhoma?" }, { who: "them", zh: "房间在八楼，电梯在左边。", sq: "Dhoma është në katin e tetë, ashensori është majtas." }, { who: "you", zh: "可以晚点退房吗？", sq: "A mund të bëj check-out pak më vonë?" }, { who: "them", zh: "可以，明天中午十二点。", sq: "Po, nesër në mesditë në orën dymbëdhjetë." }, { who: "you", zh: "谢谢。", sq: "Faleminderit." }] },
{ title: "Pyetje për rrugën në Taipei", scene: "Je në Taipei dhe po kërkon stacionin më të afërt të metrosë. Ndalon një vendas në rrugë dhe pyet me mirësjellje.", lines: [{ who: "you", zh: "请问，地铁站在哪里？", sq: "Më falni, ku është stacioni i metrosë?" }, { who: "them", zh: "一直走，然后在右边。", sq: "Ec drejt, pastaj është në të djathtë." }, { who: "you", zh: "离这里近吗？", sq: "A është afër këtu?" }, { who: "them", zh: "很近，走路五分钟。", sq: "Shumë afër, pesë minuta në këmbë." }, { who: "you", zh: "哪个出口比较方便？", sq: "Cila dalje është më e përshtatshme?" }, { who: "them", zh: "三号出口比较方便。", sq: "Dalja numër tre është më e përshtatshme." }, { who: "you", zh: "我去台北车站。", sq: "Po shkoj në Stacionin Taipei." }, { who: "them", zh: "坐红线，很快。", sq: "Merr linjën e kuqe, është shumë shpejt." }, { who: "you", zh: "在哪里换乘？", sq: "Ku ndërroj linjë?" }, { who: "them", zh: "不用换乘。", sq: "Nuk ka nevojë të ndërrosh." }, { who: "you", zh: "我明白了，谢谢。", sq: "E kuptova, faleminderit." }, { who: "them", zh: "不客气。", sq: "S’ka përse." }] },
{ title: "Darkë në një restorant në Nanjing", scene: "Je në një restorant në Nanjing me një mik. Dëshiron të porosisësh diçka jo shumë pikante dhe të kërkosh rekomandim.", lines: [{ who: "them", zh: "你好，几个人？", sq: "Përshëndetje, sa persona?" }, { who: "you", zh: "两个人。", sq: "Dy persona." }, { who: "them", zh: "这是菜单。", sq: "Kjo është menuja." }, { who: "you", zh: "谢谢。这个辣吗？", sq: "Faleminderit. A është kjo djegëse?" }, { who: "them", zh: "有一点辣。", sq: "Është pak djegëse." }, { who: "you", zh: "请不要放太多辣。", sq: "Ju lutem mos vendosni shumë djegës." }, { who: "them", zh: "好的。您吃肉吗？", sq: "Në rregull. A hani mish?" }, { who: "you", zh: "我吃鸡肉，不吃猪肉。", sq: "Ha mish pule, nuk ha mish derri." }, { who: "them", zh: "那我推荐这个菜。", sq: "Atëherë ju rekomandoj këtë pjatë." }, { who: "you", zh: "好，我要这个。", sq: "Mirë, dua këtë." }, { who: "them", zh: "还要米饭吗？", sq: "Doni edhe oriz?" }, { who: "you", zh: "要，两碗米饭。", sq: "Po, dy tasa oriz." }] },
{ title: "Blerje bilete metroje në Shenzhen", scene: "Je në Shenzhen dhe dëshiron të blesh një biletë metroje për në stacionin verior. Pyet një punonjës për ndihmë te makina e biletave.", lines: [{ who: "them", zh: "你好，需要帮助吗？", sq: "Përshëndetje, a keni nevojë për ndihmë?" }, { who: "you", zh: "需要，我要买地铁票。", sq: "Po, dua të blej biletë metroje." }, { who: "them", zh: "你要去哪里？", sq: "Ku dëshironi të shkoni?" }, { who: "you", zh: "到深圳北站。", sq: "Deri në Stacionin Verior të Shenzhenit." }, { who: "them", zh: "请选择这条线。", sq: "Ju lutem zgjidhni këtë linjë." }, { who: "you", zh: "多少钱？", sq: "Sa kushton?" }, { who: "them", zh: "六块。", sq: "Gjashtë juanë." }, { who: "you", zh: "可以用现金吗？", sq: "A mund të përdor para në dorë?" }, { who: "them", zh: "可以，也可以扫码。", sq: "Po, mundeni, mund edhe të skanoni kodin." }, { who: "you", zh: "在哪里换乘？", sq: "Ku ndërroj linjë?" }, { who: "them", zh: "下一站换乘。", sq: "Ndërroni në stacionin tjetër." }, { who: "you", zh: "谢谢你帮忙。", sq: "Faleminderit për ndihmën." }] },
{ title: "Blerje suveniresh në Kunming", scene: "Je në një treg në Kunming dhe po shikon suvenire. Dëshiron një send të vogël, në ngjyrë të kuqe, dhe përpiqesh të kërkosh çmim më të mirë.", lines: [{ who: "them", zh: "你好，喜欢哪个？", sq: "Përshëndetje, cili ju pëlqen?" }, { who: "you", zh: "我只是看看。", sq: "Vetëm po shikoj." }, { who: "them", zh: "这个很漂亮。", sq: "Kjo është shumë e bukur." }, { who: "you", zh: "这个多少钱？", sq: "Sa kushton kjo?" }, { who: "them", zh: "八十块。", sq: "Tetëdhjetë juanë." }, { who: "you", zh: "太贵了，可以便宜一点吗？", sq: "Shumë shtrenjtë, a mund të jetë pak më lirë?" }, { who: "them", zh: "七十块可以。", sq: "Shtatëdhjetë juanë bën." }, { who: "you", zh: "有红色的吗？", sq: "A ka në të kuqe?" }, { who: "them", zh: "有，这个是红色的。", sq: "Po, kjo është e kuqe." }, { who: "you", zh: "我要小的。", sq: "Dua të voglën." }, { who: "them", zh: "好的，给你。", sq: "Në rregull, ja ku e keni." }, { who: "you", zh: "谢谢。", sq: "Faleminderit." }] },
{ title: "Në farmaci në Wuhan", scene: "Nuk ndihesh mirë gjatë udhëtimit në Wuhan dhe hyn në një farmaci. Ke dhimbje koke dhe kërkon ilaç të thjeshtë.", lines: [{ who: "them", zh: "你好，请问哪里不舒服？", sq: "Përshëndetje, ku nuk ndiheni mirë?" }, { who: "you", zh: "我头疼。", sq: "Më dhemb koka." }, { who: "them", zh: "发烧吗？", sq: "Keni temperaturë?" }, { who: "you", zh: "没有发烧。", sq: "Nuk kam temperaturë." }, { who: "them", zh: "感冒了吗？", sq: "Jeni ftohur?" }, { who: "you", zh: "可能感冒了。", sq: "Ndoshta jam ftohur." }, { who: "them", zh: "这个药可以。", sq: "Ky ilaç bën." }, { who: "you", zh: "怎么用？", sq: "Si përdoret?" }, { who: "them", zh: "一天两次，饭后吃。", sq: "Dy herë në ditë, pas ushqimit." }, { who: "you", zh: "我对海鲜过敏。", sq: "Jam alergjik ndaj frutave të detit." }, { who: "them", zh: "这个药没有问题。", sq: "Ky ilaç nuk ka problem." }, { who: "you", zh: "好，谢谢。", sq: "Mirë, faleminderit." }] },
{ title: "Bisedë e vogël me një vendas në Hangzhou", scene: "Je pranë Liqenit Perëndimor në Hangzhou dhe fillon një bisedë me një vendas. Flisni për udhëtimin, ushqimin dhe përshtypjet e tua.", lines: [{ who: "you", zh: "你好，这里很美。", sq: "Përshëndetje, këtu është shumë bukur." }, { who: "them", zh: "是的，西湖很有名。", sq: "Po, Liqeni Perëndimor është shumë i famshëm." }, { who: "you", zh: "我第一次来杭州。", sq: "Është hera ime e parë në Hangzhou." }, { who: "them", zh: "你从哪里来？", sq: "Nga vjen?" }, { who: "you", zh: "我从阿尔巴尼亚来。", sq: "Vij nga Shqipëria." }, { who: "them", zh: "你喜欢中国吗？", sq: "A të pëlqen Kina?" }, { who: "you", zh: "喜欢，我觉得这里很特别。", sq: "Po, më pëlqen, më duket shumë e veçantë këtu." }, { who: "them", zh: "你吃过中国菜吗？", sq: "Ke ngrënë ushqim kinez?" }, { who: "you", zh: "吃过，很好吃。", sq: "Po, kam ngrënë, është shumë i shijshëm." }, { who: "them", zh: "下次可以去成都。", sq: "Herën tjetër mund të shkosh në Chengdu." }, { who: "you", zh: "好，下次我还想来。", sq: "Mirë, herën tjetër dua të vij përsëri." }, { who: "them", zh: "欢迎你再来。", sq: "Mirë se të vish përsëri." }] }
];
